from dataclasses import dataclass, field
from typing import Optional
from datetime import date


@dataclass
class Criterion:
    text: str
    satisfied: bool = False
    satisfied_on: Optional[date] = None
    evidence_url: Optional[str] = None

    def satisfy(self, evidence_url: str = None) -> None:
        self.satisfied = True
        self.satisfied_on = date.today()
        self.evidence_url = evidence_url


@dataclass
class Milestone:
    id: str
    name: str
    criteria: list[Criterion] = field(default_factory=list)

    @property
    def is_complete(self) -> bool:
        return all(c.satisfied for c in self.criteria)

    @property
    def completion_pct(self) -> float:
        if not self.criteria:
            return 0.0
        return sum(1 for c in self.criteria if c.satisfied) / len(self.criteria) * 100

    def status_report(self) -> str:
        lines = [f"Milestone {self.id}: {self.name}"]
        for c in self.criteria:
            mark = "✓" if c.satisfied else "○"
            lines.append(f"  {mark} {c.text}")
        lines.append(f"  Completion: {self.completion_pct:.0f}%")
        return "\n".join(lines)


@dataclass
class Phase:
    id: str
    name: str
    milestones: list[Milestone] = field(default_factory=list)

    @property
    def is_gate_ready(self) -> bool:
        return all(m.is_complete for m in self.milestones)

    def blocking_milestones(self) -> list[Milestone]:
        return [m for m in self.milestones if not m.is_complete]


# Example usage
pilot = Phase(
    id="pilot",
    name="Phase 1 — Pilot",
    milestones=[
        Milestone(
            id="M1",
            name="Use Case Selected",
            criteria=[
                Criterion("Problem statement documented and approved"),
                Criterion("Data access agreements signed"),
                Criterion("Baseline KPIs captured"),
            ],
        ),
    ],
)

# Mark criteria satisfied as evidence is gathered
pilot.milestones[0].criteria[0].satisfy(evidence_url="https://wiki/ai-strategy/use-case-doc")
pilot.milestones[0].criteria[1].satisfy(evidence_url="https://legal/agreements/data-access-v1")

print(pilot.milestones[0].status_report())
print(f"Gate ready: {pilot.is_gate_ready}")
